
UPDATE documento_templates 
SET conteudo = REPLACE(
  conteudo,
  '<p>No caso de roubo, furto, incêndio, colisão e alagamento, o associado deve comunicar imediatamente a PRATICCAR através do 0800 980 0001 o evento ocorrido sob pena de negativa de cobertura; Caso o veículo protegido pela PRATICCAR infrinja as normas do Código de Trânsito Brasileiro (CTB), tais como: conduzir na contramão de direção; avançar o sinal semafórico ou o de parada obrigatória; dirigir sob efeito de álcool ou recusar-se a realizar o teste do etilômetro; exceder o limite de velocidade; manusear/utilizar o telefone celular ou pegar objetos no interior do veículo durante a condução; bem como cometer qualquer outra infração classificada como grave ou gravíssima, os benefícios previstos no Programa de Socorro Mútuo da PRATICCAR serão automaticamente negados; O associado fica ciente que o rastreador instalado no veículo ficará sob sua responsabilidade em caráter de comodato e a não devolução do rastreador à PRATICCAR ocasionará ao associado o pagamento de uma multa estipulada em R$400,00; Os benefícios de roubo, furto, colisão, alagamento e incêndio do PSM têm início no primeiro dia útil subsequente à data de aceitação da vistoria e da instalação do equipamento de rastreamento, quando obrigatório, sendo o início no ato que ocorrer por último. Os demais benefícios só estarão disponíveis após 48 horas (quarenta e oito horas) úteis após o prazo supracitado; O ASSOCIADO declara estar ciente de que a PRATICCAR é uma associação de benefícios mútuos, regida por seu Estatuto e em conformidade com as normas legais aplicáveis. Declara, ainda, que recebeu cópia do Regulamento Associativo e do Regulamento de Assistência 24 Horas, tendo lido, compreendido e possuindo pleno conhecimento de todas as normas neles contidas, as quais aceita e com as quais concorda integralmente, estando plenamente ciente de todo o seu conteúdo.</p>',
  '<p>No caso de roubo, furto, incêndio, colisão e alagamento, o associado deve comunicar imediatamente a PRATICCAR através do <strong>0800 980 0001</strong> o evento ocorrido sob pena de negativa de cobertura.</p><p>Caso o veículo protegido pela PRATICCAR infrinja as normas do Código de Trânsito Brasileiro (CTB), tais como: conduzir na contramão de direção; avançar o sinal semafórico ou o de parada obrigatória; dirigir sob efeito de álcool ou recusar-se a realizar o teste do etilômetro; exceder o limite de velocidade; manusear/utilizar o telefone celular ou pegar objetos no interior do veículo durante a condução; bem como cometer qualquer outra infração classificada como grave ou gravíssima, os benefícios previstos no Programa de Socorro Mútuo da PRATICCAR serão automaticamente negados.</p><p>O associado fica ciente que o rastreador instalado no veículo ficará sob sua responsabilidade em caráter de comodato e a não devolução do rastreador à PRATICCAR ocasionará ao associado o pagamento de uma multa estipulada em <strong>R$400,00</strong>.</p><p>Os benefícios de roubo, furto, colisão, alagamento e incêndio do PSM têm início no primeiro dia útil subsequente à data de aceitação da vistoria e da instalação do equipamento de rastreamento, quando obrigatório, sendo o início no ato que ocorrer por último. Os demais benefícios só estarão disponíveis após 48 horas (quarenta e oito horas) úteis após o prazo supracitado.</p><p>O ASSOCIADO declara estar ciente de que a PRATICCAR é uma associação de benefícios mútuos, regida por seu Estatuto e em conformidade com as normas legais aplicáveis. Declara, ainda, que recebeu cópia do Regulamento Associativo e do Regulamento de Assistência 24 Horas, tendo lido, compreendido e possuindo pleno conhecimento de todas as normas neles contidas, as quais aceita e com as quais concorda integralmente, estando plenamente ciente de todo o seu conteúdo.</p>'
)
WHERE id = 'eb09759f-cfbc-4ee8-8f1f-f1cc520e7279';
